// ============================================================
// Scale Registry & Battery Configuration
// ============================================================
export const SCALES = {
  cbf_pi_b: CBF_PI_B,
  gses: GSES,
  dass21_stress: DASS21_STRESS,
  growth_mindset: GROWTH_MINDSET,
  sgps: SGPS,
  atmd: ATMD,
};

export const BATTERIES = {
  character: ['cbf_pi_b', 'gses', 'dass21_stress', 'sgps', 'atmd'],
  integrated: ['cbf_pi_b', 'gses', 'growth_mindset', 'sgps', 'atmd'],
};

/**
 * Get all items for a given battery, in order.
 * Returns flat array with scale_id attached to each item.
 */
export function getBatteryItems(batteryId) {
  const scaleIds = BATTERIES[batteryId];
  if (!scaleIds) return [];
  const items = [];
  for (const sid of scaleIds) {
    const scale = SCALES[sid];
    if (!scale) continue;
    for (const item of scale.items) {
      items.push({
        ...item,
        scale_id: sid,
        scale_name: scale.name,
        dimension: scale.dimension,
        options: scale.options,
        max_score: scale.options.length,
      });
    }
  }
  return items;
}

/**
 * Get metadata for all scales in a battery.
 */
export function getBatteryMeta(batteryId) {
  const scaleIds = BATTERIES[batteryId];
  if (!scaleIds) return [];
  return scaleIds.map(sid => {
    const s = SCALES[sid];
    return {
      id: s.id,
      name: s.name,
      dimension: s.dimension,
      description: s.description,
      item_count: s.items.length,
      reliability: s.reliability,
      source: s.source,
      norms: s.norms,
    };
  });
}

export default { SCALES, BATTERIES, getBatteryItems, getBatteryMeta };
